1	/**
2	 * LayerInfinite MCP Server — fail-open.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * 3-Layer failure protection with circuit breaker.
5	 *
6	 * Layer 1: Async logging fails → write to local disk queue → retry with backoff
7	 * Layer 2: LI API unreachable → fail open → agent executes directly → queue on disk
8	 * Layer 3: Everything fails → agent executes as if LI doesn't exist → zero footprint
9	 *
10	 * Circuit breaker: 3 consecutive upstream failures → open for 60s → half-open probe
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { writeFile, mkdir, readFile, unlink } from 'node:fs/promises';
15	import { join } from 'node:path';
16	import { randomUUID } from 'node:crypto';
17	import type { FailOpenState, OutcomePayload } from './types.js';
18	import { logger } from './logger.js';
19	
20	const log = logger.forTool('fail-open');
21	
22	const QUEUE_DIR = '.li-queue';
23	const CIRCUIT_BREAKER_THRESHOLD = 3;
24	const CIRCUIT_BREAKER_OPEN_MS = 60_000;
25	const MAX_QUEUE_RETRY_MS = 300_000; // 5 min max retry
26	const BASE_BACKOFF_MS = 1000;
27	
28	export function createFailOpenState(): FailOpenState {
29	  return {
30	    upstreamFailures: new Map(),
31	    circuitBreakerOpen: new Map(),
32	    lastHealthCheck: new Map(),
33	    totalRequests: 0,
34	    passthroughRequests: 0,
35	  };
36	}
37	
38	/** Ensure queue directory exists. Returns the directory path. */
39	async function ensureQueueDir(): Promise<string> {
40	  await mkdir(QUEUE_DIR, { recursive: true });
41	  return QUEUE_DIR;
42	}
43	
44	// ── Layer 1: Disk queue for failed async logs ────────────────
45	
46	export interface QueuedEntry {
47	  id: string;
48	  payload: OutcomePayload;
49	  attempts: number;
50	  firstAttempt: number;
51	  lastAttempt: number;
52	}
53	
54	/**
55	 * Write an outcome to the local disk queue when LI API is unreachable.
56	 * Each entry is a separate JSON file for atomicity.
57	 */
58	export async function enqueueOutcome(payload: OutcomePayload): Promise<void> {
59	  const dir = await ensureQueueDir();
60	  const id = randomUUID();
61	  const entry: QueuedEntry = {
62	    id,
63	    payload,
64	    attempts: 0,
65	    firstAttempt: Date.now(),
66	    lastAttempt: Date.now(),
67	  };
68	  const path = join(dir, `${id}.json`);
69	  await writeFile(path, JSON.stringify(entry) + '\n', 'utf-8');
70	  log.info('Outcome queued to disk', { id, action: payload.action_name });
71	}
72	
73	/** List all queued entries sorted by first attempt (oldest first). */
74	export async function listQueuedEntries(): Promise<QueuedEntry[]> {
75	  const { readdir } = await import('node:fs/promises');
76	  const dir = await ensureQueueDir();
77	  const entries: QueuedEntry[] = [];
78	  try {
79	    const files = await readdir(dir);
80	    for (const file of files) {
81	      if (!file.endsWith('.json')) continue;
82	      try {
83	        const content = await readFile(join(dir, file), 'utf-8');
84	        entries.push(JSON.parse(content) as QueuedEntry);
85	      } catch {
86	        // Corrupt queue file — skip
87	      }
88	    }
89	  } catch {
90	    // Directory doesn't exist yet — no entries
91	  }
92	  return entries.sort((a, b) => a.firstAttempt - b.firstAttempt);
93	}
94	
95	/** Remove a queued entry by ID. */
96	export async function dequeueEntry(id: string): Promise<void> {
97	  const dir = await ensureQueueDir();
98	  try {
99	    await unlink(join(dir, `${id}.json`));
100	  } catch {
101	    // Already removed — fine
102	  }
103	}
104	
105	/** Update attempts on a queued entry. */
106	export async function updateQueuedEntry(entry: QueuedEntry): Promise<void> {
107	  const dir = await ensureQueueDir();
108	  await writeFile(join(dir, `${entry.id}.json`), JSON.stringify(entry) + '\n', 'utf-8');
109	}
110	
111	// ── Layer 2 & 3: Circuit breaker ─────────────────────────────
112	
113	/** Record a failure for an upstream server. Returns true if circuit breaker just opened. */
114	export function recordUpstreamFailure(state: FailOpenState, upstreamName: string): boolean {
115	  const current = state.upstreamFailures.get(upstreamName) ?? 0;
116	  const next = current + 1;
117	  state.upstreamFailures.set(upstreamName, next);
118	
119	  if (next >= CIRCUIT_BREAKER_THRESHOLD && !state.circuitBreakerOpen.get(upstreamName)) {
120	    state.circuitBreakerOpen.set(upstreamName, true);
121	    log.warn('Circuit breaker opened', { upstream: upstreamName, failures: next });
122	    return true;
123	  }
124	  return false;
125	}
126	
127	/** Record a success — resets failure count and closes circuit breaker. */
128	export function recordUpstreamSuccess(state: FailOpenState, upstreamName: string): void {
129	  state.upstreamFailures.set(upstreamName, 0);
130	  if (state.circuitBreakerOpen.get(upstreamName)) {
131	    state.circuitBreakerOpen.set(upstreamName, false);
132	    log.info('Circuit breaker closed', { upstream: upstreamName });
133	  }
134	}
135	
136	/** Probe half-open: check if enough time has passed to attempt a probe.
137	 *  Does NOT reset state — the caller must call recordUpstreamSuccess/Failure
138	 *  after the actual health check completes. */
139	export function probeCircuitBreaker(state: FailOpenState, upstreamName: string): boolean {
140	  const open = state.circuitBreakerOpen.get(upstreamName);
141	  if (!open) return false;
142	
143	  const lastCheck = state.lastHealthCheck.get(upstreamName) ?? 0;
144	  if (Date.now() - lastCheck < CIRCUIT_BREAKER_OPEN_MS) return false;
145	
146	  // Allow one probe through — caller is responsible for recording result
147	  state.circuitBreakerOpen.set(upstreamName, false);
148	  log.info('Circuit breaker half-open — probing', { upstream: upstreamName });
149	  return true;
150	}
151	
152	/** Check if circuit breaker is open for an upstream. */
153	export function isCircuitOpen(state: FailOpenState, upstreamName: string): boolean {
154	  return state.circuitBreakerOpen.get(upstreamName) ?? false;
155	}
156	
157	/** Update health check timestamp. */
158	export function updateHealthCheck(state: FailOpenState, upstreamName: string): void {
159	  state.lastHealthCheck.set(upstreamName, Date.now());
160	}
161	
162	// ── Retry queue processor ────────────────────────────────────
163	
164	export type QueueSender = (payload: OutcomePayload) => Promise<boolean>;
165	
166	/**
167	 * Process the disk queue with exponential backoff.
168	 * Returns the number of entries successfully sent.
169	 */
170	export async function processQueue(send: QueueSender): Promise<number> {
171	  const entries = await listQueuedEntries();
172	  let sent = 0;
173	
174	  for (const entry of entries) {
175	    const elapsed = Date.now() - entry.firstAttempt;
176	    if (elapsed > MAX_QUEUE_RETRY_MS) {
177	      log.warn('Queue entry expired', { id: entry.id, elapsed_ms: elapsed });
178	      await dequeueEntry(entry.id);
179	      continue;
180	    }
181	
182	    const success = await send(entry.payload);
183	    if (success) {
184	      await dequeueEntry(entry.id);
185	      sent++;
186	    } else {
187	      const updated: QueuedEntry = {
188	        ...entry,
189	        attempts: entry.attempts + 1,
190	        lastAttempt: Date.now(),
191	      };
192	      await updateQueuedEntry(updated);
193	    }
194	  }
195	
196	  return sent;
197	}
198	
199	/**
200	 * Calculate backoff delay for a queue retry.
201	 * Exponential: min(base * 2^attempts, 5 min).
202	 */
203	export function backoffDelay(attempts: number): number {
204	  return Math.min(BASE_BACKOFF_MS * Math.pow(2, attempts), MAX_QUEUE_RETRY_MS);
205	}
206	
207	/** Get queue stats for monitoring. */
208	export async function getQueueStats(): Promise<{ count: number; oldestMs: number | null }> {
209	  const entries = await listQueuedEntries();
210	  return {
211	    count: entries.length,
212	    oldestMs: entries.length > 0 ? Date.now() - entries[0].firstAttempt : null,
213	  };
214	}
215	
216	// ── Queue processor lifecycle ────────────────────────────────
217	
218	/**
219	 * Start a periodic queue processor. Runs immediately on startup to drain any
220	 * entries left from a crash, then every `intervalMs` thereafter.
221	 * Returns a handle with `stop()` for clean shutdown.
222	 */
223	export function startQueueProcessor(
224	  send: QueueSender,
225	  intervalMs: number = 30_000,
226	): { stop: () => void } {
227	  // Drain on startup — catch crash leftovers immediately
228	  void processQueue(send);
229	
230	  const timer = setInterval(() => {
231	    void processQueue(send);
232	  }, intervalMs);
233	
234	  log.info('Queue processor started', { intervalMs });
235	
236	  return {
237	    stop: () => {
238	      clearInterval(timer);
239	      log.info('Queue processor stopped');
240	    },
241	  };
242	}
