1	/**
2	 * LayerInfinite MCP Server — outcome-classifier.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * LLM-based outcome classifier using GPT-4o mini. Classifies raw
5	 * tool calls into structured OutcomeClassification when the agent
6	 * does not provide explicit task_type / context / business_outcome.
7	 *
8	 * Fail-open: LLM timeout or error → null (caller falls back to
9	 * existing rule-based defaults). Never blocks the gateway.
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	import { createHash } from 'node:crypto';
14	import type { ClassifierConfig } from './config.js';
15	import type { OutcomeClassification } from './types.js';
16	import type { UpstreamCallResult } from './rest-client.js';
17	import { logger } from './logger.js';
18	
19	const log = logger.forTool('outcome-classifier');
20	
21	const SYSTEM_PROMPT = [
22	  'You are an outcome classifier. Given a tool call and its result, extract structured fields.',
23	  'Classify the task_type from this taxonomy: payment_failed, refund_processing, subscription_management, ticket_resolution, auth_recovery, order_recovery, onboarding, code_deployment, data_query, content_generation, web_search, file_operation, system_diagnostic, unspecified_issue.',
24	  'Determine business_outcome: resolved (success), partial (mixed/partial success), failed (error/unsuccessful), unknown (unclear).',
25	  'Output ONLY valid JSON matching the schema. No explanation.',
26	].join(' ');
27	
28	const TAXONOMY = new Set([
29	  'payment_failed', 'refund_processing', 'subscription_management',
30	  'ticket_resolution', 'auth_recovery', 'order_recovery',
31	  'onboarding', 'code_deployment', 'data_query', 'content_generation',
32	  'web_search', 'file_operation', 'system_diagnostic', 'unspecified_issue',
33	]);
34	
35	const VALID_OUTCOMES = new Set(['resolved', 'partial', 'failed', 'unknown']);
36	
37	// ── Helpers ────────────────────────────────────────────────────
38	
39	function truncateResult(result: UpstreamCallResult, maxChars: number): string {
40	  const texts: string[] = [];
41	  for (const item of result.content) {
42	    if (typeof item.text === 'string') texts.push(item.text);
43	    else if (typeof item.data === 'string') texts.push(item.data);
44	    else texts.push(JSON.stringify(item));
45	  }
46	  let joined = texts.join('\n');
47	  if (joined.length > maxChars) {
48	    joined = joined.slice(0, maxChars) + '…';
49	  }
50	  return joined;
51	}
52	
53	function makeSignature(toolName: string, args: Record<string, unknown>): string {
54	  const normalized = JSON.stringify(args, Object.keys(args).sort());
55	  const hash = createHash('sha256').update(`${toolName}:${normalized}`).digest('hex');
56	  return hash.slice(0, 16);
57	}
58	
59	function isValidClassification(o: unknown): o is OutcomeClassification {
60	  if (!o || typeof o !== 'object') return false;
61	  const c = o as Record<string, unknown>;
62	  return (
63	    typeof c.task_type === 'string' &&
64	    TAXONOMY.has(c.task_type) &&
65	    typeof c.context === 'string' &&
66	    typeof c.success === 'boolean' &&
67	    (c.error_message === null || typeof c.error_message === 'string') &&
68	    typeof c.result_summary === 'string' &&
69	    typeof c.business_outcome === 'string' &&
70	    VALID_OUTCOMES.has(c.business_outcome) &&
71	    typeof c.confidence === 'number' &&
72	    c.confidence >= 0 &&
73	    c.confidence <= 1
74	  );
75	}
76	
77	// ── Rule-based fallback classifier ───────────────────────────
78	
79	const ERROR_KEYWORDS = /\b(?:error|failed|denied|refused|invalid|timeout|unauthorized|forbidden|not.?found|conflict|unavailable|panic|fatal|crash)\b/i;
80	
81	/**
82	 * Rule-based classification when the LLM is unreachable.
83	 * Less accurate but always available — fail-open design.
84	 * Confidence is always 0.5 (neutral — rules are uncertain by nature).
85	 */
86	export function classifyWithRules(
87	  toolName: string,
88	  _args: Record<string, unknown>,
89	  result: { content: Array<{ type: string; [key: string]: unknown }>; isError?: boolean },
90	  isError: boolean,
91	  agentTaskType: string,
92	): OutcomeClassification {
93	  const resultText = result.content
94	    .map((item) => (typeof item.text === 'string' ? item.text : JSON.stringify(item)))
95	    .join('\n');
96	
97	  const isExplicitTaskType = agentTaskType !== 'unknown'
98	    && agentTaskType !== ''
99	    && agentTaskType !== 'unspecified_issue';
100	
101	  const task_type = isExplicitTaskType ? agentTaskType : 'unspecified_issue';
102	
103	  if (isError || result.isError === true) {
104	    return {
105	      task_type,
106	      context: `Tool "${toolName}" returned an error`,
107	      success: false,
108	      error_message: resultText.slice(0, 500) || 'Unknown error',
109	      result_summary: `Call to ${toolName} failed`,
110	      business_outcome: 'failed',
111	      confidence: 0.5,
112	    };
113	  }
114	
115	  if (ERROR_KEYWORDS.test(resultText)) {
116	    return {
117	      task_type,
118	      context: `Tool "${toolName}" result contains error indicators`,
119	      success: false,
120	      error_message: resultText.slice(0, 500),
121	      result_summary: `Call to ${toolName} indicates failure`,
122	      business_outcome: 'failed',
123	      confidence: 0.5,
124	    };
125	  }
126	
127	  if (!resultText.trim()) {
128	    return {
129	      task_type,
130	      context: `Tool "${toolName}" returned empty result`,
131	      success: true,
132	      error_message: null,
133	      result_summary: `Call to ${toolName} completed with no output`,
134	      business_outcome: 'unknown',
135	      confidence: 0.5,
136	    };
137	  }
138	
139	  return {
140	    task_type,
141	    context: `Tool "${toolName}" executed successfully`,
142	    success: true,
143	    error_message: null,
144	    result_summary: resultText.slice(0, 500),
145	    business_outcome: 'resolved',
146	    confidence: 0.5,
147	  };
148	}
149	
150	// ══════════════════════════════════════════════════════════════
151	// OutcomeClassifier
152	// ══════════════════════════════════════════════════════════════
153	
154	export class OutcomeClassifier {
155	  private readonly config: ClassifierConfig;
156	  private readonly cache = new Map<string, { storedAt: number; value: OutcomeClassification }>();
157	  private readonly inFlight = new Map<string, Promise<OutcomeClassification | null>>();
158	
159	  constructor(config: ClassifierConfig) {
160	    this.config = config;
161	  }
162	
163	  async classify(
164	    toolName: string,
165	    args: Record<string, unknown>,
166	    result: UpstreamCallResult,
167	    isError: boolean,
168	    agentTaskType: string,
169	  ): Promise<OutcomeClassification | null> {
170	    // Skip LLM if agent provided a valid explicit task_type
171	    const isExplicitTaskType = agentTaskType !== 'unknown'
172	      && agentTaskType !== ''
173	      && agentTaskType !== 'unspecified_issue';
174	
175	    if (isExplicitTaskType && !result.isError) {
176	      return null; // Agent knows best — no LLM needed for healthy calls
177	    }
178	
179	    // For error cases, always run classification regardless of agent task_type
180	    // The LLM can extract error_message and determine business_outcome accurately
181	
182	    const sig = makeSignature(toolName, args);
183	    const cacheKey = `${sig}:${isError}`;
184	
185	    // Check LRU cache
186	    const cached = this.cache.get(cacheKey);
187	    if (cached && (Date.now() - cached.storedAt) < this.config.cacheTtlMs) {
188	      log.debug('Cache hit', { toolName, cacheKey });
189	      return cached.value;
190	    }
191	
192	    // In-flight coalescing
193	    const inFlight = this.inFlight.get(cacheKey);
194	    if (inFlight) {
195	      log.debug('In-flight coalesce', { toolName, cacheKey });
196	      return inFlight;
197	    }
198	
199	    const promise = this.callLLM(toolName, args, result, isError, agentTaskType);
200	    this.inFlight.set(cacheKey, promise);
201	
202	    try {
203	      const classification = await promise;
204	      if (classification) {
205	        this.cache.set(cacheKey, { storedAt: Date.now(), value: classification });
206	      }
207	      return classification;
208	    } finally {
209	      this.inFlight.delete(cacheKey);
210	    }
211	  }
212	
213	  // ── Private ──────────────────────────────────────────────────
214	
215	  private async callLLM(
216	    toolName: string,
217	    args: Record<string, unknown>,
218	    result: UpstreamCallResult,
219	    isError: boolean,
220	    agentTaskType: string,
221	  ): Promise<OutcomeClassification | null> {
222	    if (!this.config.apiKey) {
223	      log.warn('Classifier enabled but no API key configured — skipping');
224	      return null;
225	    }
226	
227	    const controller = new AbortController();
228	    const timeout = setTimeout(() => controller.abort(), this.config.timeoutMs);
229	
230	    try {
231	      const userPrompt = JSON.stringify({
232	        tool_name: toolName,
233	        arguments: args,
234	        result: truncateResult(result, 2000),
235	        is_error: isError || result.isError === true,
236	        agent_task_type: agentTaskType,
237	      });
238	
239	      const response = await fetch(`${this.config.baseUrl}/chat/completions`, {
240	        method: 'POST',
241	        headers: {
242	          'Authorization': `Bearer ${this.config.apiKey}`,
243	          'Content-Type': 'application/json',
244	        },
245	        body: JSON.stringify({
246	          model: this.config.model,
247	          messages: [
248	            { role: 'system', content: SYSTEM_PROMPT },
249	            { role: 'user', content: userPrompt },
250	          ],
251	          temperature: 0,
252	          max_tokens: 1024,
253	          response_format: { type: 'json_object' },
254	        }),
255	        signal: controller.signal,
256	      });
257	
258	      if (!response.ok) {
259	        const text = await response.text().catch(() => '');
260	        log.warn('LLM API error', { status: response.status, text: text.slice(0, 200) });
261	        return null;
262	      }
263	
264	      const data = (await response.json()) as {
265	        choices?: Array<{ message?: { content?: string } }>;
266	      };
267	
268	      const rawContent = data.choices?.[0]?.message?.content;
269	      if (!rawContent) {
270	        log.warn('LLM returned empty response');
271	        return null;
272	      }
273	
274	      let parsed: unknown;
275	      try {
276	        parsed = JSON.parse(rawContent);
277	      } catch {
278	        log.warn('LLM returned invalid JSON', { raw: rawContent.slice(0, 200) });
279	        return null;
280	      }
281	
282	      if (!isValidClassification(parsed)) {
283	        log.warn('LLM classification failed validation', { parsed });
284	        return null;
285	      }
286	
287	      log.debug('LLM classified', {
288	        toolName,
289	        task_type: parsed.task_type,
290	        business_outcome: parsed.business_outcome,
291	        confidence: parsed.confidence,
292	      });
293	
294	      return parsed;
295	    } catch (err) {
296	      if (err instanceof DOMException && err.name === 'AbortError') {
297	        log.warn('LLM classification timed out', { timeoutMs: this.config.timeoutMs });
298	      } else {
299	        log.warn('LLM classification error', {
300	          error: err instanceof Error ? err.message : String(err),
301	        });
302	      }
303	      return null;
304	    } finally {
305	      clearTimeout(timeout);
306	      this.pruneCache();
307	    }
308	  }
309	
310	  private pruneCache(): void {
311	    const cutoff = Date.now() - this.config.cacheTtlMs;
312	    for (const [key, entry] of this.cache) {
313	      if (entry.storedAt < cutoff) {
314	        this.cache.delete(key);
315	      }
316	    }
317	  }
318	}
