143	    }
144	
145	    const controller = new AbortController();
146	    let timeoutId: ReturnType<typeof setTimeout> | null = null;
147	
148	    const timeoutPromise = new Promise<never>((_, reject) => {
149	        const onAbort = () => reject(new Error('TIMEOUT'));
150	        controller.signal.addEventListener('abort', onAbort, { once: true });
151	        // { once: true } automatically removes the listener after it fires.
152	        // This prevents listener accumulation on the happy path.
153	    });
154	
155	    timeoutId = setTimeout(
156	        () => controller.abort(),
157	        REQUEST_TIMEOUT_MS
158	    );
159	
160	    const start = Date.now();
161	
162	    try {
163	        await Promise.race([next(), timeoutPromise]);
164	    } catch (e: any) {
165	        if (e?.message === 'TIMEOUT') {
166	            const elapsed = Date.now() - start;
167	            console.warn(
168	                `[layerinfinite] Request timeout on ${c.req.path} ` +
169	                `after ${elapsed}ms`
170	            );
171	            return c.json(
172	                {
173	                    error: 'Request timeout',
174	                    code: 'GATEWAY_TIMEOUT',
175	                    timeout_ms: REQUEST_TIMEOUT_MS,
176	                },
177	                504
178	            );
179	        }
180	        throw e;
181	    } finally {
182	        if (timeoutId !== null) clearTimeout(timeoutId);
183	        // AbortController itself is GC'd after this scope ends.
184	        // No manual cleanup needed — { once: true } handles listener removal.
185	    }
186	});
