9	type Provider = 'stripe' | 'sendgrid' | 'generic';
10	type BusinessOutcome = 'resolved' | 'partial' | 'failed' | 'unknown';
11	
12	interface CanonicalWebhookPayload {
13	    outcomeId: string;
14	    finalScore: number;
15	    businessOutcome: BusinessOutcome;
16	}
17	
18	function clamp01(value: number): number {
19	    if (value < 0) return 0;
20	    if (value > 1) return 1;
21	    return value;
22	}
23	
24	function getObject(value: unknown): Record<string, unknown> {
25	    if (value && typeof value === 'object' && !Array.isArray(value)) {
26	        return value as Record<string, unknown>;
27	    }
28	    return {};
29	}
30	
31	function extractStripePayload(payloadInput: unknown): CanonicalWebhookPayload | null {
32	    const payload = getObject(payloadInput);
33	    const eventData = getObject(payload.data);
34	    const eventObject = getObject(eventData.object);
35	    const objectPayload = Object.keys(eventObject).length > 0 ? eventObject : payload;
36	
37	    const metadata = getObject(objectPayload.metadata);
38	    const outcomeId = metadata.layerinfinite_outcome_id;
39	    const amountRefunded = Number(objectPayload.amount_refunded ?? 0);
40	    const amount = Number(objectPayload.amount ?? objectPayload.amount_received ?? 0);
41	    const eventType = String(payload.type ?? objectPayload.status ?? '').toLowerCase();
42	
43	    if (typeof outcomeId !== 'string') return null;
44	
45	    let finalScore = 0.5;
46	    let businessOutcome: BusinessOutcome = 'unknown';
47	
48	    if (Number.isFinite(amount) && amount > 0 && Number.isFinite(amountRefunded) && amountRefunded > 0) {
49	        finalScore = clamp01(amountRefunded / amount);
50	        businessOutcome = finalScore >= 1 ? 'resolved' : 'partial';
51	    } else if (
52	        eventType.includes('succeeded')
53	        || eventType.includes('completed')
54	        || eventType.includes('paid')
55	    ) {
56	        finalScore = 1.0;
57	        businessOutcome = 'resolved';
58	    } else if (
59	        eventType.includes('failed')
60	        || eventType.includes('canceled')
61	        || eventType.includes('expired')
62	    ) {
63	        finalScore = 0.0;
64	        businessOutcome = 'failed';
65	    }
66	
67	    return { outcomeId, finalScore, businessOutcome };
68	}
69	
70	function extractSendgridPayload(payloadInput: unknown): CanonicalWebhookPayload | null {
71	    const events = Array.isArray(payloadInput) ? payloadInput : [payloadInput];
72	
73	    for (const eventRow of events) {
74	        const eventPayload = getObject(eventRow);
75	        if (Object.keys(eventPayload).length === 0) continue;
76	
77	        const customArgs = getObject(eventPayload.custom_args);
78	        const uniqueArgs = getObject(eventPayload.unique_args);
79	        const outcomeId = customArgs.outcome_id ?? uniqueArgs.outcome_id;
80	        const event = String(eventPayload.event ?? '').toLowerCase();
81	
82	        if (typeof outcomeId !== 'string') {
83	            continue;
84	        }
85	
86	        if (event === 'delivered' || event === 'processed') {
87	            return { outcomeId, finalScore: 1.0, businessOutcome: 'resolved' };
88	        }
89	
90	        if (
91	            event === 'bounce'
92	            || event === 'blocked'
93	            || event === 'dropped'
94	            || event === 'deferred'
95	            || event === 'spamreport'
96	        ) {
97	            return { outcomeId, finalScore: 0.0, businessOutcome: 'failed' };
98	        }
99	
100	        return { outcomeId, finalScore: 0.5, businessOutcome: 'unknown' };
101	    }
102	
103	    return null;
104	}
105	
106	function extractGenericPayload(payloadInput: unknown): CanonicalWebhookPayload | null {
107	    const payload = getObject(payloadInput);
108	    const outcomeId = payload.outcome_id;
109	    const finalScore = Number(payload.final_score);
110	    const businessOutcome = String(payload.business_outcome) as BusinessOutcome;
111	
112	    const allowedOutcomes = ['resolved', 'partial', 'failed', 'unknown'];
113	    if (typeof outcomeId !== 'string') return null;
114	    if (Number.isNaN(finalScore)) return null;
115	    if (!allowedOutcomes.includes(businessOutcome)) return null;
116	
117	    return {
118	        outcomeId,
119	        finalScore: clamp01(finalScore),
120	        businessOutcome,
121	    };
122	}
123	
124	function extractPayload(provider: Provider, payloadInput: unknown): CanonicalWebhookPayload | null {
125	    if (provider === 'stripe') return extractStripePayload(payloadInput);
126	    if (provider === 'sendgrid') return extractSendgridPayload(payloadInput);
127	    return extractGenericPayload(payloadInput);
128	}
