37	/** Resolve the rate limit ceiling for a request path. */
38	function resolveMaxRequests(path: string): number {
39	    if (path.includes('/tools/list') || path.includes('/v1/get-scores') || path.includes('/v1/recommendations')) {
40	        return getToolsListMax();
41	    }
42	    if (path.includes('/tools/call') || path.includes('/v1/log-outcome') || path.includes('/v1/simulate')) {
43	        return getToolsCallMax();
44	    }
45	    return getMaxRequests();
