328	  /** Get list of healthy upstream names (circuit closed + last health check OK). */
329	  getHealthyUpstreams(): string[] {
330	    return this.registry.getAllUpstreams()
331	      .filter((e) => this.registry.isHealthy(e.server.name))
332	      .map((e) => e.server.name);
333	  }
334	
335	  /** Start periodic health checks on all upstreams. */
336	  startHealthChecks(): void {
337	    this.registry.startHealthChecks();
338	  }
